    if (phase !== 'build' || prefersReducedMotion) return;

    const douglasLines = ASCII_DOUGLAS.split('\n').filter(line => line.trim());
    const mitchellLines = ASCII_MITCHELL.split('\n').filter(line => line.trim());
    const totalLines = douglasLines.length + mitchellLines.length;

    const typeInterval = setInterval(() => {
      if (currentLine < douglasLines.length) {
        setTypedDouglas(prev => {
          const line = douglasLines[currentLine];
          const currentTyped = prev[currentLine] || '';
          if (currentTyped.length < line.length) {
            const next = [...prev];
            next[currentLine] = line.slice(0, currentTyped.length + 4);
            return next;
          } else {
            setCurrentLine(currentLine + 1);
            return [...prev, line];
          }
        });
      } else if (currentLine < totalLines) {
        const mitchellIdx = currentLine - douglasLines.length;
        setTypedMitchell(prev => {
          const line = mitchellLines[mitchellIdx];
          const currentTyped = prev[mitchellIdx] || '';
          if (currentTyped.length < line.length) {
            const next = [...prev];
            next[mitchellIdx] = line.slice(0, currentTyped.length + 4);
            return next;
          } else {
            setCurrentLine(currentLine + 1);
            return [...prev, line];
          }
        });
      } else {
        clearInterval(typeInterval);
        setTimeout(() => setPhase('reveal'), 500);
      }
    }, 30);

    return () => clearInterval(typeInterval);
  }, [phase, currentLine, prefersReducedMotion]);

