                    style={{ backgroundColor: NORD_COLORS.cyan }}
                    initial={{ width: 0 }}
                    animate={{ width: `${progress}%` }}
                    transition={{ duration: 0.1 }}
                  />
                </div>
              </motion.div>
            )}

            {/* Footer */}
            <motion.div
